    return (NSUInteger)[self getInteger:key];
}

- (void)setSelectedFeaturesMask:(NSUInteger)mask forBundleId:(NSString *)bundleId {
    if (bundleId.length == 0) return;
    NSString *key = [NSString stringWithFormat:@"SelectedFeaturesMask_%@", bundleId];
    [self setInteger:(NSInteger)mask forKey:key];
