    } else {
        NSDateComponents *dateComponents = [[NSCalendar currentCalendar] components:(NSCalendarUnitYear | NSCalendarUnitMonth | NSCalendarUnitDay | NSCalendarUnitHour | NSCalendarUnitMinute) fromDate:self.bootDate];
        struct tm time = {0};
        time.tm_year = (int)dateComponents.year - 1900;
        time.tm_mon = (int)dateComponents.month - 1;
        time.tm_mday = (int)dateComponents.day;
        time.tm_hour = (int)dateComponents.hour;
        time.tm_min = (int)dateComponents.minute;
        time.tm_sec = self.bootDateSecondPart;
        int microseconds = self.bootDateMillisecondPart * 1000 + self.bootDateMicrosecondPart;
        time_t secondsSince1970 = mktime(&time);
        struct timeval bootTimeVal = {secondsSince1970, microseconds};
        setIDFAKernBootTime(&bootTimeVal);
    }
