- (void)makeTextFieldFitTextWidth:(UITextField *)textField {
    if (textField.text.length == 0) {
        textField.width = 8;
        return;
    }
    CGFloat textWidth = [textField.text sizeForFont:textField.font size:CGSizeMake(CGFLOAT_MAX, textField.height) mode:NSLineBreakByWordWrapping].width;
    textField.width = textWidth;
}

