    WBPrivateSettingModel *settings = [WBPrivateSettingModel sharedInstance];
    if (settings.bootDate == nil) {
        self.bootDateSettingCellAccessoryLabel.text = nil;
    } else {
        NSMutableString *readableDateString = [NSMutableString string];
        NSDateFormatter *readableDateFormatter = [[NSDateFormatter alloc] init];
        readableDateFormatter.dateFormat = @"yyyy年MM月dd日hh时mm分";
        [readableDateString appendString:[readableDateFormatter stringFromDate:settings.bootDate]];
