- (id<JUNPushNotificationUIDelegate>)_getUIDelegate {
    return [WBAPNsUIDelegate sharedDelegate];
}

- (void)registerDeviceTokenToServer:(nullable NSData *)token withVappBundleId:(NSString *)bundleId maxRetries:(NSInteger)maxRetries retryInterval:(NSTimeInterval)interval completion:(void (^)(NSString *token))completion {
    __block NSInteger attemptCount = 0;
    __weak typeof(self) weakSelf = self;

    // 弱引用 pollBlock
    void (^__block weakPollBlock)(void) = nil;

    void (^pollBlock)(void) = ^{
        [weakSelf getVirtualDeviceTokenFromServer:token withVappBundleId:bundleId completion:^(NSString *token) {
            if (token && ![token isKindOfClass:[NSNull class]]) {
                completion(token);
            } else if (++attemptCount < maxRetries) {
                dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(interval * NSEC_PER_SEC)), dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), weakPollBlock);
            } else {
                completion(nil);
            }
        }];
    };
    weakPollBlock = pollBlock;
    pollBlock();
}

- (void)getVirtualDeviceTokenFromServer:(nullable NSData *)token withVappBundleId:(NSString *)vappBundleId completion:(void(^)(NSString *token))completionHandler {
    NSString *tokenString = token != nil ? token.hexString : @"";
    [[WBNetworkManager defaultManager] sendPushToken:tokenString withVappBundleId:vappBundleId callback:^(id _Nullable json, NSError * _Nullable error) {
        if (completionHandler && json && [json isKindOfClass:[NSDictionary class]]) {
            id tokenValue = json[@"virtuallyDeviceToken"];
            NSString *virtualDeviceToken = ([tokenValue isKindOfClass:[NSNull class]]) ? nil : tokenValue;
            completionHandler(virtualDeviceToken);
        } else {
            completionHandler(nil); // 确保回调始终执行
        }
    }];
}


@end

