- (void)onActionClearCache {
    [SVProgressHUD showWithStatus:@"正在清除"];
    __block BOOL vappInstalled = false;

    for (WBPackageInfo *package in [WBVAppManager sharedManager].deleteUncleanedAppPackages) {
        [package cleanDeletedCache];
        [[WBVAppManager sharedManager].deleteUncleanedAppPackages removeObject:package];
    }
    [[WBVAppManager sharedManager] saveDeleteUncleanedAppPaths];

    for (WBVAppModel *vapp in [WBVAppManager sharedManager].myApps) {
        vappInstalled = true;// 进入了缓存清理流程
        [vapp cleanCache];
    }
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        if(vappInstalled){
            [SVProgressHUD dismiss];
        }else{
            [SVProgressHUD showSuccessWithStatus:@"清除成功！"];
        }
    });
}

- (void)onActionShowPrivilegeChanged:(id)sender {
    if ([sender isKindOfClass:WBSettingIconSwitchCell.class]) {
        WBSettingIconSwitchCell *cell = (WBSettingIconSwitchCell *)sender;
        if (cell.switchControl.on == FALSE && (!WBSettingManager.sharedManager.IsVIP && !WBSettingManager.sharedManager.IsSVIP)) {
            [SVProgressHUD showErrorWithStatus:@"您还不是会员"];
            cell.switchControl.on = TRUE;
        } else {
            WBSettingManager.sharedManager.HideVIPPrivilege = !cell.switchControl.on;
            PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
            [SVProgressHUD showSuccessWithStatus:@"设置成功"];
            [self initSettings];
            [self.tableView reloadData];
        }
    }
}

