        UIImageView *arrowImageView = [[UIImageView alloc] initWithImage:[UIImage imageNamed:@"switchVapp_button"]];
        arrowImageView.contentMode = UIViewContentModeScaleAspectFit;
        [vappSwitchButton addSubview:arrowImageView];

        [iconImageView mas_makeConstraints:^(MASConstraintMaker *make) {
