# pragma mark - GroMore NativeAd

/******** 信息流广告配置 *********/
- (void)groMoreNativeAdLoad {
    if (self.nativeAdManager) {
        // 销毁上次广告对象
        [self.nativeAdManager.mediation destory];
    }
    CGFloat adWidth = [UIScreen mainScreen].bounds.size.width;

    BUAdSlot *slot = [[BUAdSlot alloc] init];
    slot.ID = [WBSettingManager sharedManager].nativeSlotId;
    slot.adSize = CGSizeMake(adWidth, 0);
    slot.mediation.mutedIfCan = YES;
    BUNativeAdsManager *nativeAdManager = [[BUNativeAdsManager alloc] initWithSlot:slot];
    nativeAdManager.mediation.rootViewController = self;
    nativeAdManager.delegate = self;
    self.nativeAdManager = nativeAdManager;

    [self.nativeAdManager loadAdDataWithCount:1];
}


# pragma mark - BUMNativeAdsManagerDelegate

/******** 信息流广告加载回调处理 *********/

// 广告加载成功
- (void)nativeAdsManagerSuccessToLoad:(BUNativeAdsManager *)adsManager nativeAds:(NSArray<BUNativeAd *> *_Nullable)nativeAdDataArray {
    [WBEventManager logAppAdNativeLoadEvent:@"0"];
    self.nativeAdDataArray = nativeAdDataArray;
    self.nativeAdRetryCount = 0;    // 重置重试计数

    // 清理重试定时器
    if (self.nativeAdRetryTimer) {
        [self.nativeAdRetryTimer invalidate];
        self.nativeAdRetryTimer = nil;
    }

    for (BUNativeAd *model in nativeAdDataArray) {
        model.rootViewController = self;
        model.delegate = self;
        if (model.mediation.isExpressAd) {
            [model.mediation render];
        }

        // 展示广告
        if (model.mediation.canvasView) {
            [self.view addSubview:model.mediation.canvasView];

            CGFloat adWidth = [UIScreen mainScreen].bounds.size.width;
            [model.mediation.canvasView mas_makeConstraints:^(MASConstraintMaker *make) {
                make.bottom.equalTo(self.view).offset(ZOOM(700));
                make.centerX.equalTo(self.view);
                make.width.mas_equalTo(adWidth);
                make.height.mas_equalTo(adWidth * 0.25);
            }];
        }
    }
}

// 广告加载失败
- (void)nativeAdsManager:(BUNativeAdsManager *)adsManager didFailWithError:(NSError *_Nullable)error {
    [WBEventManager logAppAdNativeLoadEvent:error.localizedDescription];
    if (self.nativeAdRetryCount < self.maxNativeAdRetryCount) {
        self.nativeAdRetryCount++;

        NSTimeInterval retryInterval = self.nativeAdRetryInterval * pow(2, self.nativeAdRetryCount - 1);
        retryInterval = MIN(retryInterval, 10.0);   // 限制最大间隔为10秒

        if (self.nativeAdRetryTimer) {
            [self.nativeAdRetryTimer invalidate];
            self.nativeAdRetryTimer = nil;
        }
        self.nativeAdRetryTimer = [NSTimer scheduledTimerWithTimeInterval:retryInterval
                                                                  target:self
                                                                selector:@selector(retryNativeAdLoad)
                                                                userInfo:nil
                                                                 repeats:NO];
        [[NSRunLoop mainRunLoop] addTimer:self.nativeAdRetryTimer forMode:NSRunLoopCommonModes];
    } else {
        self.nativeAdRetryCount = 0;
        if (self.nativeAdRetryTimer) {
            [self.nativeAdRetryTimer invalidate];
            self.nativeAdRetryTimer = nil;
        }
    }
}

- (void)retryNativeAdLoad {
    [self groMoreNativeAdLoad];
}


