                            if (canOnNumber == 1) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                        }
                    }
                } else if (tip && ![tip isKindOfClass:[NSNull class]]) {
                    NSString *trimmedTip = [[tip stringValue] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
                    if (trimmedTip.length > 0) {
                        if (canOnNumber == 0) [SVProgressHUD showSuccessWithStatus:trimmedTip]; else [SVProgressHUD showErrorWithStatus:trimmedTip];
                    }
                }

                if (route && ![route isKindOfClass:[NSNull class]] && [route isKindOfClass:[NSString class]]) {
                    NSURL *routeUrl = [NSURL URLWithString:(NSString *)route];
                    [[WBRouteManager sharedManager] performRoute:routeUrl sourceInterface:@"user/notifyConnect"];
                }
            });
        }];
    };

    void (^showEnableAlert)(void (^)(void)) = ^(void (^confirmAction)(void)) {
        [[UNUserNotificationCenter currentNotificationCenter] getNotificationSettingsWithCompletionHandler:^(UNNotificationSettings *settings) {
