     UIAlertController *alertControl = [UIAlertController alertControllerWithTitle:@"确定退出吗" message:@"退出登录后我们会继续保留您的使用数据" preferredStyle:UIAlertControllerStyleAlert];

     UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:@"取消" style:UIAlertActionStyleCancel handler:^(UIAlertAction * _Nonnull action) {
     }];
     UIAlertAction *confirmAction = [UIAlertAction actionWithTitle:@"退出登录" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action) {
         [[WBNetworkManager defaultManager] getLogout:@"" callback:^(id  _Nullable json, NSError * _Nullable error) {
             if (error==nil) {
                 // 广告、任务控制
                 [[WBNetworkManager defaultManager] getAdsInfo:@"" callback:^(id  _Nullable adsJson, NSError * _Nullable error) {
                     if (error) {
                         NSLog(@"获取广告控制信息失败：%@", error.localizedDescription);
                     } else {
                         WBAdsHttpModel *adModel = [WBAdsHttpModel modelWithJSON:adsJson];
                         [WBSettingManager.sharedManager syncWithAds:adModel];
                     }

                     WBUserInfoHttpModel *model = [WBUserInfoHttpModel modelWithJSON:json];
                     [WBSettingManager.sharedManager syncWithUserInfo:model];
                     WBSettingManager.sharedManager.HideVIPPrivilege = FALSE;
                     PostNotificationOnMainThread(WBAccountStatusChangedNotification, nil);
                     [WBVAppManager.sharedManager resetAllFeaturesStatus];
                     [self.navigationController popToRootViewControllerAnimated:YES];
                 }];

                 if (!kArrayIsEmpty(WBVAppManager.sharedManager.myApps)) {
                     for (WBVAppModel *vapp in WBVAppManager.sharedManager.myApps) {
                         if (vapp.featureStatusInfo.isNotificationSwitchOn) {
                             [WBNetworkManager.defaultManager connectNotification:vapp.bundleId isOn:YES callback:^(id _Nullable json, NSError *_Nullable error) {}];
                         }
                     }
                 }
             } else {
                 NSString *descriptionStr =  error.userInfo[@"NSLocalizedDescription"];
                 [SVProgressHUD showInfoWithStatus:descriptionStr];
             }
         }];
     }];
     [alertControl addAction:cancelAction];
     [alertControl addAction:confirmAction];
     [self presentViewController:alertControl animated:YES completion:nil];
}
