@interface WBMinePrivilegeView ()

@property (nonatomic, strong) UIImageView *titleImageView;
@property (nonatomic, strong) UIView *powerView;
@property (nonatomic, strong) UIView *svipPowerView;
@property (nonatomic, strong) UIView *vipPowerView;
@property (nonatomic, strong) UIView *seperatorView;
@property (nonatomic, strong) UIImageView *onlySvipLabelImageView;
@property (nonatomic, strong) NSArray<WBMinePrivilegeButton *> *svipButtons;
