@property (nonatomic, strong) NSArray<WBVIPFeatureModel*> *features;

@end

@implementation WBMinePrivilegeView

- (instancetype)initWithFrame:(CGRect)frame {
    self = [super initWithFrame:frame];
    if (self) {
        self.features = [WBVIPFeatureManager.sharedManager getFeatures];
        [self setupUI];
    }
    return self;
}


#pragma mark - setUpUI

- (void)setupUI {
    self.backgroundColor = [UIColor clearColor];
    [self addSubviews];
    [self setupButtons];
    [self addAllConstraints];
}

- (void)addSubviews {
    [self addSubview:self.titleImageView];
    [self addSubview:self.powerView];
    [self.powerView addSubview:self.svipPowerView];
    [self.powerView addSubview:self.vipPowerView];
    [self.powerView addSubview:self.seperatorView];
    [self addSubview:self.onlySvipLabelImageView];
}

- (void)setupButtons {
    // 获取当前会员状态的配置
    NSDictionary *config = [self vipStatusConfig];
    NSString *nameKey = config[@"nameKey"];
    NSString *descKey = config[@"descKey"];

    // 创建按钮的辅助方法
    WBMinePrivilegeButton* (^createButton)(NSString *codeName, BOOL isSVIP) = ^WBMinePrivilegeButton*(NSString *codeName, BOOL isSVIP) {
        WBVIPFeatureModel *featureModel = nil;
        for (WBVIPFeatureModel *feature in self.features) {
            if ([feature.code_name isEqualToString:codeName]) {
                featureModel = feature;
                break;
            }
        }

        if (featureModel) {
            NSString *benefitDescription = nil;
            NSInteger benefitTrialTimes = 0;
            if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
                for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
                    NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
                    if (currentBenefitBit == [featureModel.bit integerValue]) {
                        id descObject = dict[@"desc"];
                        id trialTimesObject = dict[@"trialTimes"];
                        if (trialTimesObject && trialTimesObject != [NSNull null]) {
                            benefitTrialTimes = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:[featureModel.bit integerValue]];
                        } else if (descObject) {
                            benefitDescription = [dict[@"desc"] stringValue];
                        }
                        break;
                    }
                }
            }

            BOOL hasTheBenefit = (WBSettingManager.sharedManager.Benefit & [featureModel.bit unsignedIntegerValue]);
            NSString *featureName = ([featureModel valueForKey:nameKey] && hasTheBenefit) ? [featureModel valueForKey:nameKey] : featureModel.name;
            NSString *featureDescription = ([featureModel valueForKey:descKey] && hasTheBenefit) ? [featureModel valueForKey:descKey] : featureModel.desc;

            // 动态获取对应会员状态和视图类型的图标key
            NSString *iconKey = [self iconKeyForViewType:isSVIP featureBit:featureModel.bit];
            NSString *featureIcon = [featureModel valueForKey:iconKey];

            WBMinePrivilegeButton *button;
            if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
                button = [[WBMinePrivilegeButton alloc] initWithIsBelongToSVIP:isSVIP icon:featureIcon name:featureName desc:featureDescription tipDescription:benefitDescription trialTimes:benefitTrialTimes];
            } else {
                button = [[WBMinePrivilegeButton alloc] initWithIsBelongToSVIP:isSVIP icon:featureIcon name:featureName desc:featureDescription tip:@""];
            }
            button.featureCodeName = codeName;
            [button addTarget:self action:@selector(privilegeButtonClicked:) forControlEvents:UIControlEventTouchUpInside];

            return button;
        }
        return nil;
    };

    // SVIP的按钮
    NSMutableArray *svipButtonsArray = [NSMutableArray array];
    NSArray *svipFeatureCodes = @[@"adsfree", @"pretense", @"oneclick"];

    for (NSString *codeName in svipFeatureCodes) {
        WBMinePrivilegeButton *button = createButton(codeName, YES);
        if (button) {
            [svipButtonsArray addObject:button];
        }
    }
    self.svipButtons = [svipButtonsArray copy];

    // VIP的按钮
    NSMutableArray *vipButtonsArray = [NSMutableArray array];
    NSArray *vipFeatureCodes = @[@"infinite", @"lock", @"disguise", @"notification"];

    for (NSString *codeName in vipFeatureCodes) {
        WBMinePrivilegeButton *button = createButton(codeName, NO);
        if (button) {
            [vipButtonsArray addObject:button];
