- (void)updateSingleButton:(WBMinePrivilegeButton *)button isSVIPButton:(BOOL)isSVIPButton nameKey:(NSString *)nameKey descKey:(NSString *)descKey {
    if (!button.featureCodeName) return;

    WBVIPFeatureModel *featureModel = nil;
    for (WBVIPFeatureModel *feature in self.features) {
        if ([feature.code_name isEqualToString:button.featureCodeName]) {
            featureModel = feature;
            break;
        }
    }

    if (!featureModel) return;

    BOOL hasTheBenefit = (WBSettingManager.sharedManager.Benefit & [featureModel.bit unsignedIntegerValue]);
    NSString *featureName = ([featureModel valueForKey:nameKey] && hasTheBenefit) ? [featureModel valueForKey:nameKey] : featureModel.name;
    NSString *featureDescription = ([featureModel valueForKey:descKey] && hasTheBenefit) ? [featureModel valueForKey:descKey] : featureModel.desc;
    NSString *iconKey = [self iconKeyForViewType:isSVIPButton featureBit:featureModel.bit];
    NSString *featureIcon = [featureModel valueForKey:iconKey];
    [button updateWithIcon:featureIcon name:featureName desc:featureDescription];

    if (WBSettingManager.sharedManager.IsNew && WBSettingManager.sharedManager.BenefitTrialProperties.count > 0) {
        NSString *tipText = nil;
        BOOL showTip = NO;
        for (NSDictionary *dict in WBSettingManager.sharedManager.BenefitTrialProperties) {
            NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
            if (currentBenefitBit == [featureModel.bit integerValue]) {
                id trialTimesObject = dict[@"trialTimes"];
                if (trialTimesObject && trialTimesObject != [NSNull null]) {
                    NSInteger times = [WBSettingManager.sharedManager trialUsageTimesForBenefitBit:[featureModel.bit integerValue]];
                    if (times > 0) {
                        tipText = [NSString stringWithFormat:@"%ld次试用", (long)times];
                        showTip = YES;
                    }
                } else {
                    id descObject = dict[@"desc"];
                    if (descObject) {
                        tipText = [dict[@"desc"] stringValue];
                        showTip = tipText.length > 0;
                    }
                }
                break;
            }
        }
        button.tipLabel.text = tipText ?: @"";
        button.tipLabel.hidden = !showTip;
        button.tipImageView.hidden = !showTip;
    }
}


#pragma mark - 配置管理

- (NSDictionary *)vipStatusConfig {
    WBSettingManager *manager = [WBSettingManager sharedManager];
    if (manager.IsSVIP) {
        return @{
            @"titleImageName": @"MinePagePrivilegeTitleImage_svip",
            @"onlySVIPImageName": @"MinePageOnlySVIP_enable",
            @"nameKey": @"name_svip",
            @"descKey": @"desc_svip"
        };
    } else if (manager.IsVIP) {
        return @{
            @"titleImageName": @"MinePagePrivilegeTitleImage_vip",
            @"onlySVIPImageName": @"MinePageOnlySVIP_disable",
            @"nameKey": @"name_vip",
            @"descKey": @"desc_vip"
        };
    } else {
        return @{
            @"titleImageName": @"MinePagePrivilegeTitleImage",
            @"onlySVIPImageName": @"MinePageOnlySVIP_disable",
            @"nameKey": @"name",
            @"descKey": @"desc"
        };
    }
}

- (NSString *)iconKeyForViewType:(BOOL)isSVIPView featureBit:(NSString *)featureBit {
    WBSettingManager *manager = [WBSettingManager sharedManager];

    if (manager.IsSVIP) {
        if (!(manager.Benefit & [featureBit unsignedIntegerValue])) {
            return isSVIPView ? @"icon_v1" : @"icon_v0";
        } else {
            return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
        }
    }

    if (manager.IsVIP) {
        if (!(manager.Benefit & [featureBit unsignedIntegerValue])) {
            return isSVIPView ? @"icon_v1" : @"icon_v0";
        } else {
            return isSVIPView ? @"icon_v1_vip" : @"icon_v0_vip";
        }
    }

    // 处理试享权益逻辑
    if (manager.IsNew && manager.BenefitTrialProperties.count > 0) {
        for (NSDictionary *dict in manager.BenefitTrialProperties) {
            NSInteger currentBenefitBit = [dict[@"benefitBit"] integerValue];
            if (currentBenefitBit == [featureBit integerValue]) {
                id trialTimesObject = dict[@"trialTimes"];
                if (trialTimesObject && trialTimesObject != [NSNull null]) {
                    NSInteger times = [manager trialUsageTimesForBenefitBit:[featureBit integerValue]];
                    if (times <= 0) {
                        return isSVIPView ? @"icon_v1" : @"icon_v0";
                    } else {
                        return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
                    }
                } else {
                    return isSVIPView ? @"icon_v1_svip" : @"icon_v0_svip";
                }
            }
        }
        return isSVIPView ? @"icon_v1" : @"icon_v0";
    }

    // 默认返回普通图标
    return isSVIPView ? @"icon_v1" : @"icon_v0";
}


