+        [alert addAction:[UIAlertAction actionWithTitle:@"确定" style:UIAlertActionStyleDefault handler:nil]];
+        UIViewController *vc = presenter ?: [WBAppManager getUIApplicationRootViewController];
+        [vc presentViewController:alert animated:YES completion:nil];
+        return;
+    }
+
+    BOOL isTurningOn = !vapp.featureStatusInfo.isDisguiseSwitchOn;
+    BOOL canSwitch = [self handleSwitchBenefitFunction:WBUserBenefitDisguise target:isTurningOn vapp:vapp];
+    if (!canSwitch) {
+        if (setSwitch) setSwitch(NO, YES);
+        return;
+    }
+
+    if (isTurningOn) {
+        void (^successBlock)(void) = ^{
+            WBCustomVAppInfoPopViewController *fakeIconVc = [WBCustomVAppInfoPopViewController new];
+            fakeIconVc.delegate = (id)presenter;
